  'CPM stands for Cost Per ___ (cost per thousand impressions).': { prompt: 'CPM significa Costo Por ___ (costo por mil impresiones).', options: ['Mille', 'Millón', 'Mensaje', 'Mercado'], correctAnswer: 'Mille' },
