  'Data without actionable insights is just noise.': { prompt: 'Los datos sin insights accionables son solo ruido.', options: ['Verdadero', 'Falso'], correctAnswer: 'Verdadero' },

  // A/B Testing
  'What is A/B testing?': { prompt: '¿Qué es el A/B testing?', options: ['Probar entre Android y Apple', 'Comparar dos versiones de algo para ver cuál funciona mejor', 'Probar tus productos A y B', 'Un sistema de calificación'], correctAnswer: 'Comparar dos versiones de algo para ver cuál funciona mejor' },
  'You should only change one variable at a time in an A/B test.': { prompt: 'Deberías cambiar solo una variable a la vez en un test A/B.', options: ['Verdadero', 'Falso'], correctAnswer: 'Verdadero' },
  'Statistical ___ means the test result is likely not due to chance.': { prompt: 'La ___ estadística significa que el resultado del test probablemente no se debe al azar.', options: ['Significancia', 'Análisis', 'Promedio', 'Desviación'], correctAnswer: 'Significancia' },
  'What can you A/B test?': { prompt: '¿Qué puedes testear con A/B?', options: ['Solo sitios web', 'Titulares, CTAs, imágenes, emails, landing pages y más', 'Solo emails', 'Solo anuncios'], correctAnswer: 'Titulares, CTAs, imágenes, emails, landing pages y más' },
