  'What is the "control" in an A/B test?': { prompt: '¿Qué es el "control" en un test A/B?', options: ['La nueva versión', 'La versión original contra la que estás probando', 'Una selección aleatoria', 'La versión perdedora'], correctAnswer: 'La versión original contra la que estás probando' },
