  'Which A/B testing approach is better?': { prompt: '¿Qué enfoque de A/B testing es mejor?', options: ['Cambiar 5 cosas a la vez y ver qué pasa.', 'Probar un elemento a la vez con suficiente tráfico para resultados claros.'], correctAnswer: 'Probar un elemento a la vez con suficiente tráfico para resultados claros.' },
  'Small changes like button color can sometimes significantly impact conversions.': { prompt: 'Cambios pequeños como el color de un botón pueden impactar significativamente las conversiones.', options: ['Verdadero', 'Falso'], correctAnswer: 'Verdadero' },

  // Funnels
  'What is a marketing funnel?': { prompt: '¿Qué es un embudo de marketing?', options: ['Una herramienta de cocina', 'El recorrido desde el conocimiento hasta la compra que siguen los clientes', 'Un filtro de redes sociales', 'Un diseño de sitio web'], correctAnswer: 'El recorrido desde el conocimiento hasta la compra que siguen los clientes' },
