  'What is a landing page?': { prompt: '¿Qué es una landing page?', options: ['Tu página de inicio', 'Una página independiente diseñada para un objetivo de marketing específico', 'Cualquier página de tu sitio web', 'Un blog post'], correctAnswer: 'Una página independiente diseñada para un objetivo de marketing específico' },
